      cloudUploadButton.title = this.t('folder_cloud_upload');
      cloudUploadButton.addEventListener('click', () => this.handleCloudUpload());
      // Add dynamic tooltip on mouseenter
      cloudUploadButton.addEventListener('mouseenter', async () => {
